import { useState, useEffect } from "react";
import useGetDate from "../Hooks/useGetDate";

const Apodrange = () => {

  let now = new Date();
  let date = useGetDate(now);

  const [startDate, setStartDate] = useState(undefined);
  const [endDate, setEndDate] = useState(undefined);
  const [today, setToday] = useState(null);
  const [warning, setWarning] = useState('Please select a range!');
  const [apods, setApods] = useState(null);

  // transforms date into date readable by apod
  function transformDate(date)  {
    function returnDate(date) {
      let today = date.getDate();

      if (today < 10) {
        today = `0${today}`;
      }

      return today;
    }

    function returnMonth(date) {
      let month = date.getMonth() + 1;

      if (month < 10) {
        month = `0${month}`;
      }

      return month;
    }

    let currentDate = date.getFullYear() + "-" + returnMonth(date) + "-" + returnDate(date);

    return currentDate;
  }

  // increases date by two
  // function increaseDay(value) {
  //   let newValue = new Date(value);
  //   let date = newValue.getDate();
  //   newValue.setDate(date + 2);

  //   let newDate = transformDate(newValue);
  //   return newDate;
  // }

  function handleStartDate(e) {
    let value = e.target.value;
    // let newValue = increaseDay(value);
    setStartDate(value);
  }

  function handleEndDate(e) {
    let value = e.target.value;
    // let newValue = increaseDay(value);
    setEndDate(value);
    console.log(value);
  }

  const getPictures = async(e) => {
    e.preventDefault();
    console.log('click!');
    if (!(startDate && endDate)) {
      setWarning('You need a start and end date!');
      return;
    }

    const apiKey = 'hK9L5EdqbSfX3VLvK84iefSH0yV3te6DYTv1JLG4';
    let url = `https://api.nasa.gov/planetary/apod?api_key=${apiKey}&start_date=${startDate}&end_date=${endDate}`;

    const response = await fetch(url, {
      method: 'GET'
    });
    const data = await response.json();
    setApods(data);
    console.log(data);
    
    if (!response.ok) {
      throw new Error(response.status);
    }
  }

  const createApodImage = (apod) => {
    return (
      <>
        <div className="multi-apod-img">
          <p className="apod-date">{apod.date}</p>
          <img src={apod.url} alt={apod.title} className="apod-img" />
          
          
          <button className="info-btn">Info</button>
          <div className="apod-info">
            <p className="apod-title">{apod.title}</p>
            <p className="apod-explanation">{apod.explanation}</p>
            {apod.copyright && <p className="apod-copyright">Copyright: {apod.copyright}</p>}
            <a href={apod.url} className="apod-url">Click to open image in window</a>
          </div>

        </div>
      </>
    )
  }

  const createApodVideo = (apod) => {
    return (
      <>
        <div className="multi-apod-video">
          <p className="apod-date">{apod.date}</p>
          <iframe src={apod.url} frameborder="0" className="apod-video"></iframe>
        </div>
      </>
    )
  }

  useEffect(() => {
    setToday(date);
  }, []);

  useEffect(() => {
    if (!apods) return;


    // return () => {
    //   cleanup
    // }
  }, [apods])

  return (
    <div className="range-div">
      <div className="selection-div">
        <h1>Select your range:</h1>
        <div class="date-div">
          <form>
            <div className="start-container">
              <label htmlFor="start">Start date (earliest date: 06-16-1995): </label>
              <input type="date" id="start" name="apod-start" min="1995-06-16" max={endDate ? endDate : today} value={startDate} onChange={handleStartDate}/>
            </div>
            
            <div className="end-container">
              <label htmlFor="end">End date: </label>
              <input type="date" id="end" name="apod-end" min={startDate ? startDate : '1995-06-17'} max={today} value={endDate} onChange={handleEndDate}/>
            </div>            
            <button className="update-btn" onClick={getPictures}>Update pictures</button>
          </form>
        </div>
      </div>
      <div className="images-cont">{apods 
          ? apods.map(apod => {
            if (apod.media_type === 'image') {
              return createApodImage(apod);
            } else if (apod.media_type === 'video') {
              return createApodVideo(apod);
            }
          })
          : warning}</div>
    </div>
  )
}

export default Apodrange
